content.text:
// ❌ Bad: Too short (1 sentence)
description: "Check stock price"

// ✅ Good: 3–4 sentences
description: "Get the current stock price for a given symbol. Use this when you need real-time stock prices, not historical data. Returns the price in USD with timestamp. Do not use for stock analysis or company information."

// ❌ Bad: No trigger
description: "Check weather"

// ✅ Good: Explicit trigger
description: "Get the current weather for a location. Use this when you need real-time weather data, not forecasts. Returns temperature, conditions, and humidity. Do not use for historical weather or long-term forecasts."

const schema = {
  name: "get_stock_price",
  description: "Get the current stock price for a given symbol. Use this when you need real-time stock prices, not historical data.",
  input_schema: {
    type: "object",
    properties: {
      symbol: {
        // ❌ Bad: No description
        type: "string"
      },
      // ✅ Good: Descriptive
      symbol: {
        type: "string",
        description: "Stock symbol (e.g., 'AAPL' for Apple). Use uppercase letters only. Do not use company names."
      }
    },
    required: ["symbol"]
  }
};

// ❌ Bad: No output info
description: "Get stock price for symbol"

// ✅ Good: Explicit output
description: "Get the current stock price for a given symbol. Use this when you need real-time stock prices. Returns the price in USD with timestamp (e.g., { price: 175.43, timestamp: '2026-01-01T12:00:00Z' })."

// ❌ Bad: Doesn't say when to avoid
description: "Query database for user data"

// ✅ Good: Explicit avoidance
description: "Execute SQL query against the database. Use this to fetch or update user data, not for simple lookups that can be answered from context. Returns results as JSON array. Do not use for DROP, DELETE, or schema changes without explicit approval."

// ❌ Bad: Generic names
properties: {
  q: { type: "string" },
  n: { type: "integer" }
}

// ✅ Good: Descriptive names
properties: {
  query: { type: "string", description: "SQL query to execute" },
  timeout: { type: "integer", description: "Timeout in seconds" }
}

// ❌ Bad: One tool does everything
description: "Do everything: get weather, stock, query DB, send email"

// ✅ Good: One thing per tool
description: "Get the current weather for a location. Use this when you need real-time weather data."

description: "Get the current stock price for a given symbol. Use this when you need real-time stock prices."

description: "Execute SQL query against the database. Use this to fetch or update user data."

// ❌ Bad: Vague use case
description: "Get information about stocks"

// ✅ Good: Specific use case
description: "Get the current stock price for a given symbol. Use this when you need real-time stock prices for trading decisions, not for company research or historical analysis. Returns price in USD."

properties: {
  symbol: {
    type: "string",
    description: "Stock symbol (e.g., 'AAPL' for Apple, 'GOOGL' for Google). Use uppercase letters only."
  },
  location: {
    type: "string",
    description: "City name or location (e.g., 'Boston', 'New York City', 'London, UK'). Use city names, not coordinates."
  }
}

// AWS Bedrock supports user-provided examples
const tool = {
  name: "get_stock_price",
  description: "Get the current stock price for a given symbol.",
  input_schema: { ... },
  user_examples: [
    {
      input: { symbol: "AAPL" },
      output: { price: 175.43, timestamp: "2026-01-01T12:00:00Z" }
    }
  ]
};

{
  name: "get_weather",
  description: "Get the current weather for a location. Use this when you need real-time weather data, not forecasts. Returns temperature, conditions, and humidity. Do not use for historical weather or long-term forecasts.",
  input_schema: {
    type: "object",
    properties: {
      location: {
        type: "string",
        description: "City name or location (e.g., 'Boston', 'New York City'). Use city names, not coordinates."
      }
    },
    required: ["location"]
  }
}

{
  name: "query_database",
  description: "Execute SQL query against the database. Use this to fetch or update user data, not for simple lookups that can be answered from context. Returns results as JSON array. Do not use for DROP, DELETE, or schema changes without explicit approval.",
  input_schema: {
    type: "object",
    properties: {
      query: {
        type: "string",
        description: "SQL query to execute (e.g., 'SELECT * FROM users WHERE id = ?', 'INSERT INTO users...')"
      },
      params: {
        type: "array",
        description: "Query parameters for placeholders (e.g.,  [claudeinsider](https://www.claudeinsider.com/docs/api/tool-use) for 'WHERE id = ?'). Optional if no placeholders in query."
      }
    },
    required: ["query"]
  }
}

{
  name: "run_tests",
  description: "Run the test suite. Use this to verify code changes work after making modifications. Returns test results with pass/fail counts and output. Do not use for running production code or scripts unrelated to testing.",
  input_schema: {
    type: "object",
    properties: {
      command: {
        type: "string",
        description: "Test command (e.g., 'npm test', 'pytest', 'go test'). Use the appropriate command for the project's test framework."
      },
      timeout: {
        type: "integer",
        description: "Timeout in seconds (e.g., 60). Default is 30 seconds if not provided. Use for slow tests or large suites."
      },
      verbose: {
        type: "boolean",
        description: "Enable verbose output (true/false). Default is false. Use for debugging test failures."
      }
    },
    required: ["command"]
  }
}

{
  name: "read_file",
  description: "Read the contents of a file from the filesystem. Use this when you need to examine source code, configuration files, or data files. Returns file contents as string. Do not use for binary files or files larger than 100KB without explicit approval.",
  input_schema: {
    type: "object",
    properties: {
      path: {
        type: "string",
        description: "File path (e.g., 'src/auth.ts', '/var/log/app.log'). Use relative paths from project root."
      }
    },
    required: ["path"]
  }
}

{
  name: "fetch_stock_price",
  description: "Fetch the current stock price from an external API. Use this when you need real-time stock prices for trading decisions, not for company research or historical analysis. Returns price in USD with timestamp. Do not use for stock analysis, market trends, or company financials.",
  input_schema: {
    type: "object",
    properties: {
      symbol: {
        type: "string",
        description: "Stock symbol (e.g., 'AAPL' for Apple, 'GOOGL' for Google). Use uppercase letters only. Do not use company names."
      },
      exchange: {
        type: "string",
        description: "Optional exchange (e.g., 'NASDAQ', 'NYSE'). If not provided, uses default exchange. Use for multi-listed stocks."
      }
    },
    required: ["symbol"]
  }
}
